object ConfigService {

  private val configStore = TrieMap[String, Map[String, String]]()

  def parseAndExtractSettings(xmlString: String): Map[String, String] = {
    val xml = XML.loadString(xmlString)
    val settings = (xml \\ "setting").map { node =>
      (node \@ "name") -> node.text
    }.toMap
    settings
  }

  val route: Route =
    path("parse-config") {
      post {
        entity(as[String]) { xmlString =>
          try {
            val settings = parseAndExtractSettings(xmlString)
