            configStore.put("current", settings)
            complete(StatusCodes.OK, s"Configuration parsed and stored: $settings")
          } catch {
            case e: Exception =>
              complete(StatusCodes.BadRequest, s"Invalid XML: ${e.getMessage}")
          }
        }
      }
    }
